parameters.jsonBody:
={
  "trigger_id": "{{ $json.trigger_id }}",
  "view": {
    "type": "modal",
    "callback_id": "apo_action",
    "private_metadata": "{{ JSON.stringify({channel_id: $json.channel_id, user_id: $json.user_id, user_name: $json.user_name}) }}",
    "title": { "type": "plain_text", "text": "📌 アポ追加 / キャンセル" },
    "submit": { "type": "plain_text", "text": "送信" },
    "close": { "type": "plain_text", "text": "閉じる" },
    "blocks": [
      {
        "type": "input", "block_id": "action_type",
        "label": { "type": "plain_text", "text": "区分" },
        "element": {
          "type": "static_select", "action_id": "value",
          "placeholder": { "type": "plain_text", "text": "選択" },
          "options": [
            { "text": { "type": "plain_text", "text": "アポ追加" }, "value": "add" },
            { "text": { "type": "plain_text", "text": "リシェジュール" }, "value": "reschedule" },
            { "text": { "type": "plain_text", "text": "キャンセル（失注）" }, "value": "cancel_lost" },
            { "text": { "type": "plain_text", "text": "キャンセル（連絡不能）" }, "value": "cancel_unreachable" },
            { "text": { "type": "plain_text", "text": "キャンセル（顧客都合）" }, "value": "cancel_customer" }
          ]
        }
      },
      {
        "type": "input", "block_id": "customer_code",
        "label": { "type": "plain_text", "text": "顧客匿名コード" },
        "element": { "type": "plain_text_input", "action_id": "value", "placeholder": { "type": "plain_text", "text": "例: CUST-A" } }
      },
      {
        "type": "input", "block_id": "deal_code",
        "label": { "type": "plain_text", "text": "案件 ID（任意）" },
        "element": { "type": "plain_text_input", "action_id": "value", "placeholder": { "type": "plain_text", "text": "DEAL-2026-00000" } },
        "optional": true
      },
      {
        "type": "input", "block_id": "apo_datetime",
        "label": { "type": "plain_text", "text": "アポ日時" },
        "element": { "type": "datetimepicker", "action_id": "value" }
      },
      {
        "type": "input", "block_id": "reason",
        "label": { "type": "plain_text", "text": "理由 / メモ" },
        "element": { "type": "plain_text_input", "action_id": "value", "multiline": true },
        "optional": true
      }
    ]
  }
}
